.emoji-picker {
    display: flex;
    gap: 2px;
    background: var(--bs-body-bg, #fff);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 8px;
    padding: 4px 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    position: absolute;
    bottom: 100%;
    right: 0;
    z-index: 10;
    margin-bottom: 4px;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 4px 6px;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.emoji-option:hover {
    background: var(--bs-secondary-bg, #e9ecef);
}

@using sv_b1c9daff858c4901abf059649e44be99.Services

<div class="message-bubble @(_isHovered ? "hovered" : "")"
     @onmouseenter="() => _isHovered = true"
     @onmouseleave="OnMouseLeave">

