toolArgs.file_text:
@using sv_b1c9daff858c4901abf059649e44be99.Services

<div class="message-bubble @(_isHovered ? "hovered" : "")"
     @onmouseenter="() => _isHovered = true"
     @onmouseleave="OnMouseLeave">

    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@TimeFormatHelper.ToRelativeTime(Message.SentAt)</span>
    </div>

    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-bar">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync(reaction.Emoji)" title="@string.Join(", ", reaction.Users)">
                    <span class="reaction-emoji">@reaction.Emoji</span>
                    <span class="reaction-count">@reaction.Users.Count</span>
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_isHovered)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync()" title="Reply in thread">
                💬 Reply
            </button>
            <div class="react-wrapper">
                <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                    😊 React
                </button>
                @if (_showEmojiPicker)
                {
                    <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private bool _isHovered;
    private bool _showEmojiPicker;

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private void OnMouseLeave()
    {
        _isHovered = false;
        _showEmojiPicker = false;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }
}

