toolArgs.file_text:
.message-bubble {
    padding: 6px 12px;
    border-radius: 6px;
    position: relative;
    transition: background-color 0.15s;
}

.message-bubble.hovered {
    background: var(--bs-secondary-bg, #f8f9fa);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: var(--bs-secondary-color, #6c757d);
}

.message-content {
    font-size: 0.93rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: var(--bs-secondary-bg, #e9ecef);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.82rem;
    cursor: pointer;
    line-height: 1.4;
}

.reaction-badge:hover {
    background: var(--bs-primary-bg-subtle, #cfe2ff);
    border-color: var(--bs-primary-border-subtle, #9ec5fe);
}

.reaction-emoji {
    font-size: 0.95rem;
}

.reaction-count {
    font-size: 0.78rem;
    font-weight: 600;
}

.thread-link {
    background: none;
    border: none;
    color: var(--bs-primary, #0d6efd);
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -14px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: var(--bs-body-bg, #fff);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

.action-btn {
    background: none;
    border: none;
    font-size: 0.78rem;
    padding: 3px 8px;
    border-radius: 4px;
    cursor: pointer;
    white-space: nowrap;
    color: var(--bs-body-color, #212529);
}

.action-btn:hover {
    background: var(--bs-secondary-bg, #e9ecef);
}

.react-wrapper {
    position: relative;
}

