arguments.file_text:
@using sv_b1c9daff858c4901abf059649e44be99.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5 class="sidebar-title">Channels</h5>
    </div>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                @if (!string.IsNullOrWhiteSpace(channel.Description))
                {
                    <div class="channel-desc">@Truncate(channel.Description, 50)</div>
                }
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: var(--bs-dark, #212529);
    color: var(--bs-light, #f8f9fa);
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-title {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 0;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background: var(--bs-primary, #0d6efd);
    color: #fff;
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
