@using sv_b1c9daff858c4901abf059649e44be99.Services

<div class="thread-panel">
    <div class="thread-header">
        <h6 class="thread-title">Thread</h6>
        <button class="btn-close btn-close-sm" @onclick="OnClose" aria-label="Close thread"></button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-replies-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var reply in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@TimeFormatHelper.ToRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <div class="thread-input-area">
            <textarea class="form-control thread-textarea"
                      placeholder="Reply…"
                      @bind="ReplyText"
                      @onkeydown="HandleKeyDown"
                      rows="2"></textarea>
            <button class="btn btn-primary btn-sm reply-btn" @onclick="HandleReply" disabled="@string.IsNullOrWhiteSpace(ReplyText)">
                Reply
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private string ReplyText { get; set; } = string.Empty;

    private async Task HandleReply()
    {
        if (string.IsNullOrWhiteSpace(ReplyText)) return;
        var text = ReplyText;
        ReplyText = string.Empty;
        await OnSendReply.InvokeAsync(text);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleReply();
        }
    }
}

