arguments.file_text:
.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
}

@page "/chat"
@layout sv_b1c9daff858c4901abf059649e44be99.Components.Layout.ChatLayout
@rendermode InteractiveServer
@using sv_b1c9daff858c4901abf059649e44be99.Services
@using sv_b1c9daff858c4901abf059649e44be99.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_threadRootMessage is null ? "full-width" : "")">
        <MessageArea Messages="_messages"
                     CurrentChannel="_currentChannel"
                     ThreadReplyCounts="_threadReplyCounts"
                     HasMoreMessages="_hasMoreMessages"
                     IsLoadingMore="_isLoadingMore"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage"
                     OnLoadMore="LoadMoreMessages" />
    </div>

    @if (_threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         ThreadMessages="_threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private int _selectedChannelId;
    private Channel? _currentChannel;
    private const int PageSize = 30;
    private bool _hasMoreMessages = true;
    private bool _isLoadingMore;

    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];
    private Dictionary<int, int> _threadReplyCounts = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _currentChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _hasMoreMessages = true;
        _threadRootMessage = null;
        _threadMessages = [];
        _threadReplyCounts = [];

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _hasMoreMessages = messages.Count >= PageSize;

        ComputeThreadReplyCounts();

        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channel list to update unread counts
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || !_hasMoreMessages || _currentChannel is null) return;

        _isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(_currentChannel.Id, _messages.Count, PageSize);
        _hasMoreMessages = older.Count >= PageSize;
        _messages.InsertRange(0, older);
        ComputeThreadReplyCounts();
        _isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (_currentChannel is null) return;
        var message = await ChatService.SendMessageAsync(_currentChannel.Id, content, null);
        _messages.Add(message);
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadMessages = await ChatService.GetThreadAsync(messageId);
    }

    private void CloseThread()
    {
        _threadRootMessage = null;
        _threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _currentChannel is null) return;

        var reply = await ChatService.SendMessageAsync(_currentChannel.Id, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);

        // Update the reply count displayed on the root message
        _threadReplyCounts[_threadRootMessage.Id] = _threadMessages.Count;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to reflect the new reaction
        if (_currentChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_currentChannel.Id, 0, _messages.Count);
        }
    }

    private void ComputeThreadReplyCounts()
    {
        // Messages with a ReplyToId are replies; count them per root message
        _threadReplyCounts = _messages
